{
  "model": "qwen-plus",
  "messages": [
    {
      "role": "system",
      "content": "你是一个代码审查助手，优先指出会导致线上事故的问题。"
    },
    {
      "role": "user",
      "content": "请审查下面的 diff，并按严重程度排序。"
    }
  ],
  "temperature": 0.2,
  "stream": false
}

```go
func BuildPrompt(messages []Message) string {
    var b strings.Builder
    for _, msg := range messages {
        b.WriteString(msg.Role)
        b.WriteString(": ")
        b.WriteString(msg.Content)
        b.WriteString("

")
    }
    return b.String()
}
